async () => {
  const docs = await stellarDocs.search_rpc_horizon_data_docs({
    query: "simulateTransaction simulate contract invocation return value",
    hitsPerPage: 5,
    includeContent: true
  });

  if (!docs.ok) return { error: docs.error };

  const hits = (docs.data.hits || []).map(h => ({
    title: h.title,
    url: h.url,
    snippet: h.snippet,
    content: h.content || ""
  }));

  const best = hits.find(h => /simulateTransaction/i.test(h.title + " " + h.url + " " + h.content)) || hits[0] || null;

  return {
    bestHit: best ? {
      title: best.title,
      url: best.url,
      snippet: best.snippet,
      contentSample: best.content.slice(0, 1500)
    } : null,
    hitTitles: hits.slice(0, 5).map(h => ({ title: h.title, url: h.url }))
  };
}

