async () => {
  const rfps = await scout.getRfps({ limit: 100, status: "open" });

  const summarize = (items) => items.map(r => ({
    title: r.title || r.name || null,
    slug: r.slug || null,
    category: r.category || null,
    status: r.status || null,
    url: r.url || r.link || r.website || null,
    summary: r.summary || r.description || r.brief || null,
    updatedAt: r.updatedAt || r.updated_at || r.lastUpdated || r.modified_at || null,
    closesAt: r.closesAt || r.closes_at || r.deadline || null
  }));

  if (!rfps.ok) {
    return { asOf: new Date().toISOString(), error: rfps.error };
  }

  const rows = Array.isArray(rfps.data?.rfps) ? rfps.data.rfps : Array.isArray(rfps.data?.items) ? rfps.data.items : [];
  const q = /passkey|passkeys|webauthn|smart account|smart accounts/i;
  const matches = rows.filter(r => q.test(JSON.stringify(r)));

  return {
    asOf: new Date().toISOString(),
    openCount: rows.length,
    matchingCount: matches.length,
    matches: summarize(matches).slice(0, 8)
  };
}

