async () => {
  const queries = [
    'developer activity',
    'active development',
    'github commits releases contributors',
    'recent protocol development',
    'wallet sdk infrastructure updates'
  ];

  const contentCalls = await Promise.all(
    queries.map(query => lumenloop.search_content_semantic({ query, limit: 10 }))
  );

  const scoreBySlug = new Map();
  const evidenceBySlug = new Map();

  for (const call of contentCalls) {
    if (!call.ok || !Array.isArray(call.data.results)) continue;
    for (const item of call.data.results) {
      const contentId = item?.id;
      const contentType = item?.content_type || item?.type;
      const title = item?.title || item?.name || null;
      const date = item?.publishing_date || item?.created_at || item?.date || null;
      if (!contentId || !contentType) continue;
      const related = await lumenloop.get_related_projects({ content_id: contentId, content_type: contentType });
      if (!related.ok || !Array.isArray(related.data.projects)) continue;
      for (const p of related.data.projects) {
        const slug = p?.slug;
        const projectTitle = p?.title || slug;
        if (!slug) continue;
        scoreBySlug.set(slug, (scoreBySlug.get(slug) || 0) + 1);
        const arr = evidenceBySlug.get(slug) || [];
        if (arr.length < 5) arr.push({ contentTitle: title, date, contentType });
        evidenceBySlug.set(slug, arr);
      }
    }
  }

  const top = Array.from(scoreBySlug.entries())
    .map(([slug, mentions]) => ({ slug, mentions, evidence: evidenceBySlug.get(slug) || [] }))
    .sort((a, b) => b.mentions - a.mentions)
    .slice(0, 5);

  const detailCalls = await Promise.all(
    top.map(item => lumenloop.get_project({ slug: item.slug, compact: true }))
  );

  const enriched = top.map((item, i) => {
    const detail = detailCalls[i];
    return {
      slug: item.slug,
      title: detail.ok ? (detail.data.title || item.slug) : item.slug,
      category: detail.ok ? detail.data.category || null : null,
      mentions: item.mentions,
      activityBasis: 'Count of semantically matched recent development-activity content items linked to the project via related-project mapping',
      sampleEvidence: item.evidence.slice(0, 3)
    };
  });

  return {
    method: 'Semantic search over development-activity queries, then count linked content mentions per project',
    top5: enriched,
    notes: {
      queries,
      contentCallsOk: contentCalls.filter(r => r.ok).length,
      distinctProjectsRanked: scoreBySlug.size
    }
  };
}

