async () => {
  const repos = await scout.searchRepos({
    query: "zk soroban proof verifier arkworks groth16 noir circom bls12-381",
    language: "Rust",
    onlyWithReadme: true,
    limit: 8
  });

  const refs = await codemode.skill.read("skills.stellar-dev.zk-proofs", {
    sections: [
      "what-s-available-verify-before-building",
      "references",
      "walkthrough-noir-off-chain-verify-attestation-for-now"
    ]
  });

  const selected = repos.ok
    ? repos.data.repos.map(r => ({
        repo: r.fullName || r.repo || r.name || null,
        name: r.name || null,
        owner: r.owner || null,
        url: r.url || r.htmlUrl || null,
        description: r.description || null,
        stars: r.stars || r.stargazersCount || null,
        forks: r.forks || null,
        updatedAt: r.updatedAt || r.pushedAt || null,
        topics: Array.isArray(r.topics) ? r.topics.slice(0, 8) : [],
        languages: r.languages || r.language || null,
        score: r.score || null
      })) : [];

  const repoNames = selected.map(r => (r.repo || "").toLowerCase());
  const highSignal = selected.filter(r => {
    const text = [r.repo, r.description, ...(r.topics || [])].join(" ").toLowerCase();
    return (
      text.includes("soroban") ||
      text.includes("stellar") ||
      text.includes("groth16") ||
      text.includes("zk") ||
      text.includes("verifier") ||
      text.includes("arkworks")
    );
  }).slice(0, 6);

  const refsText = refs.ok
    ? JSON.stringify(refs.sections || refs.content || "")
    : "";

  const canonicalMentions = [
    "groth16_verifier example",
    "soroban-examples",
    "bls12-381 sdk docs",
    "circom",
    "snarkjs",
    "noir",
    "risc zero"
  ].filter(k => refsText.toLowerCase().includes(k.toLowerCase()));

  return {
    reposOk: repos.ok,
    repoCount: selected.length,
    highSignal,
    activityCaveat: selected.map(r => ({ repo: r.repo, updatedAt: r.updatedAt, stars: r.stars })).slice(0, 8),
    skillTakeaways: refs.ok ? {
      canonicalMentions,
      notes: [
        "Skill says to verify current primitive availability before building.",
        "Skill notes Noir flow is off-chain verify + attestation for now."
      ]
    } : null,
    repoError: repos.ok ? null : repos.error,
    refsError: refs.ok ? null : refs.error
  };
}

