async () => {
  const docs = await stellarDocs.search_wallet_dapp_docs({
    query: "wallet recovery seed phrase passkey social recovery account recovery",
    hitsPerPage: 6,
    includeContent: true
  });

  const walletSkill = await codemode.skill.read("skills.stellar-dev.dapp", {
    sections: ["wallet-integration"]
  });

  const docHits = docs.ok
    ? (docs.data.hits || []).slice(0, 6).map(h => ({
        title: h.title,
        url: h.url,
        snippet: h.snippet
      }))
    : [];

  const recoveryHits = docs.ok
    ? (docs.data.hits || [])
        .filter(h => {
          const text = `${h.title || ""} ${h.snippet || ""} ${h.content || ""}`.toLowerCase();
          return text.includes("recover") || text.includes("recovery") || text.includes("seed") || text.includes("passkey");
        })
        .slice(0, 5)
        .map(h => ({ title: h.title, url: h.url, snippet: h.snippet }))
    : [];

  const walletSection = walletSkill.ok
    ? (walletSkill.sections && walletSkill.sections["wallet-integration"]) || walletSkill.content || null
    : null;

  const walletRecoveryMentions = walletSection
    ? String(walletSection)
        .split('\n')
        .filter(line => /recover|recovery|seed|passkey|key/i.test(line))
        .slice(0, 8)
    : [];

  return {
    docsOk: docs.ok,
    docsError: docs.ok ? null : docs.error,
    topDocHits: docHits,
    recoveryFocusedHits: recoveryHits,
    skillOk: walletSkill.ok,
    skillError: walletSkill.ok ? null : walletSkill.error,
    walletRecoveryMentions
  };
}

