input.code:
async () => {
  const activity = await lumenloop.search_content_semantic({
    query: "development activity github commits releases contributors roadmap engineering updates",
    limit: 20,
    types: ["article", "av", "event", "research"]
  });

  if (!activity.ok) {
    return { error: activity.error };
  }

  const items = activity.data.results || activity.data.hits || activity.data.items || [];
  const scored = new Map();

  for (const item of items) {
    const contentId = item.id || item.content_id;
    const contentType = item.content_type || item.type;
    if (!contentId || !contentType) continue;

    const rel = await lumenloop.get_related_projects({ content_id: contentId, content_type: contentType });
    if (!rel.ok) continue;

    const projects = rel.data.projects || rel.data.results || [];
    for (const p of projects) {
      const slug = p.slug;
      const title = p.title || p.name || slug;
      if (!slug) continue;
      const row = scored.get(slug) || { slug, title, mentions: 0, basis: [] };
      row.mentions += 1;
      if (row.basis.length < 3) {
        row.basis.push({
          contentType,
          contentTitle: item.title || item.name || item.headline || "untitled"
        });
      }
      scored.set(slug, row);
    }
  }

  const top = Array.from(scored.values())
    .sort((a, b) => b.mentions - a.mentions)
    .slice(0, 5);

  const details = await Promise.all(top.map(t => lumenloop.get_project({ slug: t.slug, compact: true })));

  const enriched = top.map((t, i) => {
    const d = details[i];
    return {
      slug: t.slug,
      title: d.ok ? (d.data.title || t.title) : t.title,
      category: d.ok ? d.data.category : undefined,
      activityBasis: `${t.mentions} related recent semantic matches about development activity`,
      exampleSources: t.basis
    };
  });

  return {
    method: "Ranked projects by count of semantically matched content about development activity, then mapped content to projects via related-project links.",
    contentSampleCount: items.length,
    top5: enriched
  };
}

