async () => {
  const rfps = await scout.getRfps({ limit: 100 });
  const now = new Date().toISOString();
  const rows = rfps.ok && Array.isArray(rfps.data?.rfps) ? rfps.data.rfps : [];
  const open = rows.filter(r => String(r.status || '').toLowerCase() === 'open');
  const relevant = open.filter(r => {
    const txt = `${r.title || ''} ${r.description || ''} ${r.category || ''} ${r.tags || ''}`.toLowerCase();
    return txt.includes('passkey') || txt.includes('smart account') || txt.includes('smart accounts') || txt.includes('wallet');
  }).slice(0, 10).map(r => ({
    id: r.id || r.slug || null,
    title: r.title || null,
    category: r.category || null,
    status: r.status || null,
    deadline: r.deadline || r.due_date || r.closing_date || null,
    link: r.url || r.link || null,
    matchedOn: [
      ...(String(r.title || '').toLowerCase().includes('passkey') ? ['title:passkey'] : []),
      ...(String(r.title || '').toLowerCase().includes('smart account') || String(r.title || '').toLowerCase().includes('smart accounts') ? ['title:smart accounts'] : []),
      ...(String(r.description || '').toLowerCase().includes('passkey') ? ['desc:passkey'] : []),
      ...(String(r.description || '').toLowerCase().includes('smart account') || String(r.description || '').toLowerCase().includes('smart accounts') ? ['desc:smart accounts'] : [])
    ]
  }));
  return {
    asOf: now,
    totalReturned: rows.length,
    openCount: open.length,
    relevantCount: relevant.length,
    relevant
  };
}

