async () => {
  const dir = await lumenloop.search_directory({ query: "ZK Soroban", limit: 10 });
  const projectRows = dir.ok && dir.data.projects ? dir.data.projects.slice(0, 8).map(p => ({ slug: p.slug, title: p.title, category: p.category, tags: p.tags, website: p.website })) : [];

