  for (const p of projectRows) {
    const related = await lumenloop.find_content_about_project({ query: p.title, limit: 5 });
    activity.push({
      slug: p.slug,
      title: p.title,
      category: p.category,
      website: p.website,
      relatedCount: related.ok && related.data.results ? related.data.results.length : 0,
      relatedSamples: related.ok && related.data.results ? related.data.results.slice(0, 2).map(r => ({ type: r.type, title: r.title, date: r.date || r.publishing_date || r.created_at, url: r.url })) : [],
      caveat: related.ok && related.data.results && related.data.results.length > 0 ? 'has recent ecosystem mentions' : 'limited recent mentions in indexed sources'
    });
  }

  activity.sort((a, b) => b.relatedCount - a.relatedCount);
  return {
    queryResultCount: dir.ok && dir.data.count ? dir.data.count : (dir.ok && dir.data.projects ? dir.data.projects.length : 0),
    selected: activity.slice(0, 6)
  };
}

