  const [rfps, skillRead] = await Promise.all([
    scout.getRfps({ limit: 100 }),
    codemode.skill.read('skills.stellar-light.stellar-scout', { sections: ['data-freshness', 'evidence-floor', 'specialized-workflows'] })
  ]);

  const now = new Date().toISOString();
  const open = [];
  if (rfps.ok && rfps.data && Array.isArray(rfps.data.rfps)) {
    for (const r of rfps.data.rfps) {
      const text = `${r.title || ''} ${r.description || ''} ${(r.tags || []).join(' ')}`.toLowerCase();
      const isOpen = String(r.status || '').toLowerCase() === 'open' || String(r.phase || '').toLowerCase() === 'open' || !r.status;
      if (isOpen && (text.includes('passkey') || text.includes('smart account') || text.includes('smart accounts') || text.includes('webauthn'))) {
        open.push({ id: r.id || r.slug || null, title: r.title || null, status: r.status || r.phase || null, category: r.category || null, url: r.url || null });
      }
    }
  }

  return {
    currentAsOf: now,
    rfpsCall: rfps.ok ? { count: rfps.data.rfps.length } : { error: rfps.error },
    matchingOpenRfps: open.slice(0, 10),
    evidenceNotes: skillRead.ok ? skillRead.content.sections?.map?.(s => s.title || s.section || s.key).slice(0, 5) : { error: skillRead.error }
  };
}

