async () => {
  const [projectsRes, leaderboardRes] = await Promise.all([
    scout.searchProjects({ query: 'development activity', limit: 10 }),
    scout.searchProjects({ query: 'active builders', limit: 10 })
  ]);

  const pickRows = (res) => (res.ok && res.data && Array.isArray(res.data.projects) ? res.data.projects : []);
  const rowsA = pickRows(projectsRes);
  const rowsB = pickRows(leaderboardRes);

  const merged = new Map();
  for (const row of [...rowsA, ...rowsB]) {
    const key = row.slug || row.id || row.name;
    if (!merged.has(key)) merged.set(key, row);
  }

  const rows = [...merged.values()];
  const scored = rows.map((r) => {
    const activity = r.development_activity ?? r.activity ?? r.dev_activity ?? r.builders ?? null;
    return {
      name: r.name || r.title || r.slug,
      slug: r.slug,
      category: r.category,
      basis: activity,
      status: r.status,
      source: r.source || r.sources || undefined
    };
  }).filter(r => r.name);

  return {
    totalCandidates: scored.length,
    top5: scored.slice(0, 5),
    notes: {
      projectsQueryOk: projectsRes.ok,
      leaderboardQueryOk: leaderboardRes.ok,
      projectsError: projectsRes.ok ? null : projectsRes.error,
      leaderboardError: leaderboardRes.ok ? null : leaderboardRes.error
    }
  };
}

