async () => {
  const [repos, activitySection] = await Promise.all([
    scout.searchRepos({ language: 'Rust', limit: 12 }),
    codemode.skill.read('skills.stellar-light.stellar-scout#companion-skills', { sections: ['stellar-developer-activity'] })
  ]);

  const repoRows = repos.ok ? (repos.data.repos || repos.data.results || []).filter(Boolean) : [];
  const picked = repoRows
    .filter(r => {
      const text = `${r.name || ''} ${r.owner || ''} ${r.description || ''} ${JSON.stringify(r.topics || [])}`.toLowerCase();
      return text.includes('zk') || text.includes('zero-knowledge') || text.includes('soroban');
    })
    .slice(0, 6)
    .map(r => ({
      repo: r.fullName || r.name || r.slug,
      stars: r.stars ?? r.stargazersCount ?? null,
      updatedAt: r.updatedAt || r.pushedAt || null,
      language: r.language || null,
      topics: (r.topics || []).slice(0, 5),
      description: r.description || null
    }));

  return {
    repos: picked,
    caveat: repos.ok
      ? 'Use recency as a caveat: prefer repos with recent updates/pushes and active stars; treat older ZK/Soroban repos as study references, not current implementation signal.'
      : repos.error,
    activityGuide: activitySection.ok ? activitySection.content : activitySection.error
  };
}

