  const [rfps, skillSection] = await Promise.all([
    scout.getRfps({ limit: 50 }),
    codemode.skill.read("skills.stellar-dev.dapp", { sections: ["smart-accounts-passkey-wallets"] })
  ]);

  let openPasskey = [];
  let openSmartAccount = [];
  let allOpen = [];

  if (rfps.ok && Array.isArray(rfps.data.rfps)) {
    allOpen = rfps.data.rfps.filter(r => r.status === "open" || r.status === "Open");
    const textMatches = (r) => {
      const hay = `${r.title || ""} ${r.description || ""} ${r.summary || ""} ${r.tags?.join(" ") || ""}`.toLowerCase();
      return {
        passkey: /passkey|webauthn|passwordless|fido/i.test(hay),
        smart: /smart account|smart wallet|account abstraction|4337|soroban account/i.test(hay)
      };
    };
    openPasskey = allOpen.filter(r => textMatches(r).passkey);
    openSmartAccount = allOpen.filter(r => textMatches(r).smart);
  }

  return {
    currentAsOf: rfps.ok ? rfps.data.generatedAt || rfps.data.timestamp || null : null,
    totalOpenRfps: allOpen.length,
    passkeyMatches: openPasskey.map(r => ({ id: r.id, title: r.title, status: r.status, url: r.url, category: r.category })),
    smartAccountMatches: openSmartAccount.map(r => ({ id: r.id, title: r.title, status: r.status, url: r.url, category: r.category })),
    skillNote: skillSection.ok ? skillSection.sections?.["smart-accounts-passkey-wallets"]?.slice(0, 400) : skillSection.error,
    rfpsError: rfps.ok ? null : rfps.error
  };
}

