async () => {
  // Use Scout's project search to find active Stellar projects
  const projects = await scout.searchProjects({ limit: 20 });

  if (!projects.ok) {
    return { error: projects.error };
  }

  // Return top projects with available fields
  const topProjects = projects.data.projects?.slice(0, 10) || [];

  return {
    total: projects.data.projects?.length || 0,
    topProjects: topProjects.map(p => ({
      name: p.name,
      category: p.category,
      status: p.status,
      description: p.description?.slice(0, 200),
      github: p.githubUrl,
      website: p.websiteUrl,
      scfAwards: p.scfAwards,
      tags: p.tags
    }))
  };
}

