async () => {
  // Read ZK skill playbook sections and search for ZK Soroban repos in parallel
  const [skillAvailable, skillRefs, skillNoir, reposZk, reposSoroban] = await Promise.all([
    codemode.skill.read("skills.stellar-dev.zk-proofs", { sections: ["what-s-available-verify-before-building"] }),
    codemode.skill.read("skills.stellar-dev.zk-proofs", { sections: ["references"] }),
    codemode.skill.read("skills.stellar-dev.zk-proofs", { sections: ["walkthrough-noir-off-chain-verify-attestation-for-now"] }),
    scout.searchRepos({ query: "zk zero-knowledge", limit: 20 }),
    scout.searchRepos({ query: "soroban", limit: 20 })
  ]);

  // Helper to extract repo list safely
  const repoList = (res) => {
    if (!res.ok || !res.data) return [];
    // Scout searchRepos likely returns { repos: [...] } or { data: [...] }
    const payload = res.data.repos || res.data.data || res.data;
    return Array.isArray(payload) ? payload : [];
  };

  const zkRepos = repoList(reposZk);
  const sorobanRepos = repoList(reposSoroban);

  // Find overlap / ZK + Soroban repos by name/topic/description
  const zkTerms = /zero.?knowledge|zk.?proof|zkp|groth16|snark|stark|noir|risc.?zero|circom|bls12/i;
  const sorobanTerms = /soroban|stellar/i;

  const combined = [...zkRepos, ...sorobanRepos].filter(r =>
    zkTerms.test((r.name || "") + " " + (r.description || "") + " " + (r.topics || []).join(" ")) &&
    sorobanTerms.test((r.name || "") + " " + (r.description || "") + " " + (r.topics || []).join(" "))
  );

  // Deduplicate by full_name
  const seen = new Set();
  const unique = [];
  for (const r of combined) {
    const key = r.full_name || r.name || r.id;
    if (!seen.has(key)) {
      seen.add(key);
      unique.push(r);
    }
  }

  // Get deep explanations for top unique repos
  const topRepos = unique.slice(0, 5);
  const explanations = await Promise.all(
    topRepos.map(r =>
      scout.explainRepo({
        repo: r.full_name,
        q: "What is this repo about, what ZK or Soroban primitives does it use, and how active is it?"
      })
    )
  );

  return {
    skill: {
      available: skillAvailable.ok ? skillAvailable.sections?.["what-s-available-verify-before-building"] : skillAvailable.error,
      references: skillRefs.ok ? skillRefs.sections?.["references"] : skillRefs.error,
      noir: skillNoir.ok ? skillNoir.sections?.["walkthrough-noir-off-chain-verify-attestation-for-now"] : skillNoir.error
    },
    repoSearch: {
      zkTotal: zkRepos.length,
      sorobanTotal: sorobanRepos.length,
      matchedUnique: unique.length
    },
    topRepos: topRepos.map((r, i) => ({
      full_name: r.full_name,
      name: r.name,
      description: r.description,
      language: r.language,
      stars: r.stargazers_count || r.stars,
      updated_at: r.updated_at,
      pushed_at: r.pushed_at,
      topics: (r.topics || []).slice(0, 8),
      explanation: explanations[i].ok ? explanations[i].data : explanations[i].error
    }))
  };
}

